mapper.select:
SELECT U.USER_ID AS RANK_ID, U.NICKNAME, NVL(U.EXP, 0) AS TOTAL_EXP, ROW_NUMBER() OVER (ORDER BY NVL(U.EXP, 0) DESC, U.USER_ID ASC) AS RANKING, NVL( (
SELECT MAX(LR.LEVEL_NO) FROM LQ_LEVEL_RANGE LR WHERE NVL(U.EXP, 0) >= NVL(LR.MIN_EXP, 0) AND (LR.MAX_EXP IS NULL OR NVL(U.EXP, 0) <= LR.MAX_EXP)
), FLOOR(NVL(U.EXP, 0) / 500) + 1 ) AS LEVEL_NO FROM LQ_USER U WHERE UPPER(NVL(U.STATUS, 'ACTIVE')) = 'ACTIVE' ORDER BY RANKING ASC
